evaluators.evaluation_logic:
const checkpoints = [];

const selectedPlanId = localStorage.getItem('task1_selectedPlanId') || null;
let checkoutViewedRaw = localStorage.getItem('task1_checkoutViewed');
let checkoutViewed = false;
if (checkoutViewedRaw !== null) {
  try { checkoutViewed = JSON.parse(checkoutViewedRaw); } catch (e) { checkoutViewed = checkoutViewedRaw === 'true'; }
}

const plans = JSON.parse(localStorage.getItem('plans') || '[]');
const changes = JSON.parse(localStorage.getItem('subscription_changes') || '[]');

const selectedPlan = plans.find(p => p && p.id === selectedPlanId) || null;

const planQualifies = !!selectedPlan &&
  selectedPlan.status === 'active' &&
  typeof selectedPlan.monthly_price === 'number' && selectedPlan.monthly_price < 20 &&
  Array.isArray(selectedPlan.billing_cycles_available) && selectedPlan.billing_cycles_available.includes('annual') &&
  (
    (typeof selectedPlan.channel_count === 'number' && selectedPlan.channel_count >= 100) ||
    (Array.isArray(selectedPlan.tags) && selectedPlan.tags.includes('100_plus_channels'))
  );

const changeForPlan = changes.find(c => c && c.selected_plan_id === selectedPlanId && c.selected_billing_cycle === 'annual') || null;

// CP1 (0.40): User selected a plan that meets all criteria (annual, < $20/mo, 100+ channels).
checkpoints.push({ passed: !!selectedPlanId && planQualifies, weight: 0.40 });

// CP2 (0.35): Draft subscription change reflects that qualifying plan with annual billing selected.
checkpoints.push({ passed: !!changeForPlan && planQualifies, weight: 0.35 });

// CP3 (0.25): Checkout was viewed while that qualifying annual plan was selected in the draft.
checkpoints.push({ passed: !!changeForPlan && planQualifies && !!checkoutViewed, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let selection = null;
const selectionRaw = localStorage.getItem('task2_addonSelection');
if (selectionRaw) {
  try { selection = JSON.parse(selectionRaw); } catch (e) { selection = null; }
}

const subscriptions = JSON.parse(localStorage.getItem('subscriptions') || '[]');
const subscriptionAddons = JSON.parse(localStorage.getItem('subscription_addons') || '[]');
const changes = JSON.parse(localStorage.getItem('subscription_changes') || '[]');
const addons = JSON.parse(localStorage.getItem('addons') || '[]');

const currentSub = subscriptions.find(s => s && s.is_current) || null;
const selectedAddon = selection ? addons.find(a => a && a.id === selection.addonId) || null : null;

const addonQualifies = !!selectedAddon &&
  selectedAddon.status === 'active' &&
  selectedAddon.category === 'sports' &&
  typeof selectedAddon.monthly_price === 'number' && selectedAddon.monthly_price < 10 &&
  !!selectedAddon.has_hd_channels &&
  typeof selectedAddon.included_channels_count === 'number' && selectedAddon.included_channels_count >= 5;

// CP1 (0.40): User's recorded selection targets a qualifying sports add-on for the current subscription.
const cp1Passed = !!selection && !!currentSub && selection.subscriptionId === currentSub.id && addonQualifies;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.30): A subscription change includes this qualifying add-on in its selected_addon_ids.
const changeHasAddon = !!selectedAddon && changes.some(c => c && Array.isArray(c.selected_addon_ids) && c.selected_addon_ids.includes(selectedAddon.id));
checkpoints.push({ passed: addonQualifies && changeHasAddon, weight: 0.30 });

// CP3 (0.30): The qualifying add-on is now active on the subscription (saved configuration).
const activeSubAddon = !!selectedAddon && !!currentSub && subscriptionAddons.some(sa => sa && sa.subscription_id === currentSub.id && sa.addon_id === selectedAddon.id && sa.is_active);
checkpoints.push({ passed: addonQualifies && activeSubAddon, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const favorites = JSON.parse(localStorage.getItem('favorite_channels') || '[]');
const channels = JSON.parse(localStorage.getItem('channels') || '[]');

let favoritesListViewedRaw = localStorage.getItem('task3_favoritesListViewed');
let favoritesListViewed = false;
if (favoritesListViewedRaw !== null) {
  try { favoritesListViewed = JSON.parse(favoritesListViewedRaw); } catch (e) { favoritesListViewed = favoritesListViewedRaw === 'true'; }
}

const getChannel = id => channels.find(c => c && c.id === id) || null;

const englishMovieFavs = favorites.filter(f => {
  const ch = getChannel(f.channel_id);
  return ch && ch.genre === 'movies' && ch.primary_language === 'English';
});

const spanishNewsFavs = favorites.filter(f => {
  const ch = getChannel(f.channel_id);
  return ch && ch.genre === 'news' && ch.primary_language === 'Spanish';
});

const kidsAllAgesFavs = favorites.filter(f => {
  const ch = getChannel(f.channel_id);
  return ch && ch.genre === 'kids' && ch.rating === 'all_ages';
});

const hasAllThreeTypes = englishMovieFavs.length > 0 && spanishNewsFavs.length > 0 && kidsAllAgesFavs.length > 0;

// CP1 (0.70): At least one favorite of each required type has been added.
checkpoints.push({ passed: hasAllThreeTypes, weight: 0.70 });

// CP2 (0.30): Favorites list has been viewed after having all three qualifying types.
checkpoints.push({ passed: hasAllThreeTypes && !!favoritesListViewed, weight: 0.30 });

return checkPointsReduce(checkpoints);

function checkPointsReduce(cps) {
  return cps.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
}

const checkpoints = [];

const auth = JSON.parse(localStorage.getItem('auth_state') || 'null');
const parentalArr = JSON.parse(localStorage.getItem('parental_controls') || '[]');
const setting = parentalArr[0] || null;

// CP1 (0.40): User is signed in as the expected parent account.
const cp1Passed = !!auth && auth.is_authenticated === true && auth.email === 'parent@example.com';
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.30): A 4-digit numeric parental PIN is configured.
const cp2Passed = !!setting && typeof setting.pin === 'string' && /^[0-9]{4}$/.test(setting.pin);
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): Max content rating is TV-14 and purchases are blocked without PIN.
const cp3Passed = !!setting && setting.max_content_rating === 'tv_14' && setting.block_purchases_without_pin === true;
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let comparedIds = [];
const comparedRaw = localStorage.getItem('task5_comparedPlanIds');
if (comparedRaw) {
  try { comparedIds = JSON.parse(comparedRaw) || []; } catch (e) { comparedIds = []; }
}

let upgradeResult = null;
const upgradeRaw = localStorage.getItem('task5_upgradeResult');
if (upgradeRaw) {
  try { upgradeResult = JSON.parse(upgradeRaw); } catch (e) { upgradeResult = null; }
}

const plans = JSON.parse(localStorage.getItem('plans') || '[]');
const subscriptions = JSON.parse(localStorage.getItem('subscriptions') || '[]');
const changes = JSON.parse(localStorage.getItem('subscription_changes') || '[]');

const affordablePlans = plans.filter(p => p && p.status === 'active' && typeof p.monthly_price === 'number' && p.monthly_price <= 30);

// CP1 (0.30): User compared at least two plans that are each under or equal to $30/month.
const comparedAffordable = comparedIds
  .map(id => plans.find(p => p && p.id === id) || null)
  .filter(p => p && typeof p.monthly_price === 'number' && p.monthly_price <= 30);
const cp1Passed = comparedAffordable.length >= 2;
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// CP2 (0.35): Upgrade result selects the qualifying affordable plan with the highest simultaneous streams, improving over previous streams.
let cp2Passed = false;
if (upgradeResult && typeof upgradeResult === 'object') {
  const newPlan = plans.find(p => p && p.id === upgradeResult.newPlanId) || null;
  const prevPlan = plans.find(p => p && p.id === upgradeResult.previousPlanId) || null;
  if (newPlan && prevPlan && newPlan.status === 'active' && typeof newPlan.monthly_price === 'number' && newPlan.monthly_price <= 30) {
    const maxStreams = affordablePlans.length > 0 ? Math.max.apply(null, affordablePlans.map(p => p.max_simultaneous_streams || 0)) : null;
    const newStreams = upgradeResult.newStreams;
    const prevStreams = upgradeResult.previousStreams;
    cp2Passed = maxStreams != null &&
      newPlan.max_simultaneous_streams === maxStreams &&
      typeof newStreams === 'number' && newStreams === newPlan.max_simultaneous_streams &&
      typeof prevStreams === 'number' && newStreams > prevStreams;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): Subscription and subscription_change reflect the upgrade to that plan, effective immediately.
let cp3Passed = false;
if (upgradeResult && typeof upgradeResult === 'object') {
  const currentSub = subscriptions.find(s => s && s.is_current) || null;
  const newPlan = plans.find(p => p && p.id === upgradeResult.newPlanId) || null;
  if (currentSub && newPlan) {
    const subOk = currentSub.current_plan_id === newPlan.id &&
      (currentSub.simultaneous_streams_limit == null || currentSub.simultaneous_streams_limit >= (newPlan.max_simultaneous_streams || 0));
    const effectiveOk = upgradeResult.effectiveDateOption === 'immediately';
    const changeOk = changes.some(c => c && c.status === 'completed' && c.selected_plan_id === newPlan.id && c.effective_date_option === 'immediately');
    cp3Passed = subOk && effectiveOk && changeOk;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const recordings = JSON.parse(localStorage.getItem('recordings') || '[]');
const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const auth = JSON.parse(localStorage.getItem('auth_state') || 'null');

// In this dataset, the 'upcoming Friday' relative to 2026-03-03 is 2026-03-06.
const targetDate = '2026-03-06';
const targetTime = '20:00:00';

const qualifyingRecordings = recordings.filter(r => {
  if (!r || typeof r.keep_days !== 'number' || r.keep_days !== 7) return false;
  const prog = programs.find(p => p && p.id === r.program_id) || null;
  if (!prog) return false;
  if (prog.genre !== 'sports' || !prog.start_time) return false;
  const datePart = prog.start_time.slice(0, 10);
  const timePart = prog.start_time.slice(11, 19);
  return datePart === targetDate && timePart === targetTime;
});

// CP1 (0.40): At least one recording is for a sports program on the correct Friday at 8 PM, kept for 7 days.
checkpoints.push({ passed: qualifyingRecordings.length >= 1, weight: 0.40 });

// CP2 (0.30): User is authenticated (required to successfully schedule the recording).
const cp2Passed = !!auth && auth.is_authenticated === true;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): At least one qualifying recording is in 'scheduled' state (not canceled/failed).
const hasScheduledQualifying = qualifyingRecordings.some(r => r.status === 'scheduled');
checkpoints.push({ passed: hasScheduledQualifying, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subscriptions = JSON.parse(localStorage.getItem('subscriptions') || '[]');
const billingSettingsArr = JSON.parse(localStorage.getItem('billing_settings') || '[]');
const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');
const changes = JSON.parse(localStorage.getItem('subscription_changes') || '[]');
const plans = JSON.parse(localStorage.getItem('plans') || '[]');
const auth = JSON.parse(localStorage.getItem('auth_state') || 'null');

const currentSub = subscriptions.find(s => s && s.is_current) || null;
const billingSettings = billingSettingsArr[0] || null;
const save20 = promoCodes.find(p => p && p.code === 'SAVE20' && p.is_active) || null;

// CP1 (0.30): There is a draft or completed subscription_change with annual billing and SAVE20 applied.
const changeWithSave20Annual = changes.find(c => c && c.promo_code_code === 'SAVE20' && c.selected_billing_cycle === 'annual') || null;
checkpoints.push({ passed: !!changeWithSave20Annual && !!save20, weight: 0.30 });

// CP2 (0.35): Current subscription is on annual billing with a total annual price under $200.
let cp2Passed = false;
if (currentSub && currentSub.billing_cycle === 'annual' && typeof currentSub.total_annual_price === 'number') {
  cp2Passed = currentSub.total_annual_price < 200;
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): A completed subscription_change ties SAVE20, annual billing, and the current plan together, and the estimated new annual total is under $200; user is authenticated.
let cp3Passed = false;
if (auth && auth.is_authenticated && auth.email === 'parent@example.com' && currentSub) {
  const completedChange = changes.find(c => c && c.status === 'completed' && c.promo_code_code === 'SAVE20' && c.selected_billing_cycle === 'annual' && c.selected_plan_id === currentSub.current_plan_id) || null;
  if (completedChange) {
    const estAnnualOk = typeof completedChange.estimated_new_annual_total !== 'number' || completedChange.estimated_new_annual_total < 200;
    cp3Passed = estAnnualOk;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let playbackInfo = null;
const playbackRaw = localStorage.getItem('task8_playbackInfo');
if (playbackRaw) {
  try { playbackInfo = JSON.parse(playbackRaw); } catch (e) { playbackInfo = null; }
}

const seriesArr = JSON.parse(localStorage.getItem('series') || '[]');
const episodes = JSON.parse(localStorage.getItem('episodes') || '[]');

const selectedEpisode = playbackInfo ? episodes.find(e => e && e.id === playbackInfo.episodeId) || null : null;
const selectedSeries = playbackInfo ? seriesArr.find(s => s && s.id === playbackInfo.seriesId) || null : null;

// Determine all series that qualify as nature-related 4K documentary series.
const qualifyingSeries = seriesArr.filter(s => {
  if (!s || !s.is_active) return false;
  if (s.genre !== 'documentary') return false;
  if (s.resolution !== '4k') return false;
  if (s.content_type !== 'series') return false;
  if (!Array.isArray(s.tags)) return false;
  const tagsLower = s.tags.map(t => (t || '').toLowerCase());
  return tagsLower.includes('nature');
});

const maxPopularity = qualifyingSeries.length > 0 ? Math.max.apply(null, qualifyingSeries.map(s => s.popularity_score || 0)) : null;

// CP1 (0.40): Playback info exists and the selected series matches required filters (4K, documentary, nature-related series).
const cp1Passed = !!playbackInfo && !!selectedSeries && !!selectedEpisode &&
  selectedSeries.is_active &&
  selectedSeries.genre === 'documentary' &&
  selectedSeries.resolution === '4k' &&
  selectedSeries.content_type === 'series' &&
  Array.isArray(selectedSeries.tags) && selectedSeries.tags.map(t => (t || '').toLowerCase()).includes('nature') &&
  selectedEpisode.series_id === selectedSeries.id;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.30): The played series is the most popular among all qualifying 4K nature documentary series.
let cp2Passed = false;
if (cp1Passed && maxPopularity != null) {
  cp2Passed = (selectedSeries.popularity_score || 0) === maxPopularity;
}
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): The played episode is the first episode of that series.
let cp3Passed = false;
if (cp1Passed) {
  const episodesForSeries = episodes.filter(e => e && e.series_id === selectedSeries.id);
  if (episodesForSeries.length > 0) {
    const withOrder = episodesForSeries.map(e => ({ ep: e, order: e.episode_order != null ? e.episode_order : e.episode_number }));
    const minOrder = Math.min.apply(null, withOrder.map(x => x.order));
    const firstEpisode = withOrder.find(x => x.order === minOrder).ep;
    cp3Passed = firstEpisode && firstEpisode.id === selectedEpisode.id;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
